using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut = new();

    private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] entries) =>
        entries.Select(e => new OrderItem { ProductName = e.Name, Price = e.Price, Quantity = e.Qty }).ToList();

    // --- CreateOrder: happy path ---

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 3));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(30.00m, order.Total);
        Assert.AreEqual(1, order.Items.Count);
        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
        Assert.IsTrue(order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_SumsTotalCorrectly()
    {
        // Arrange
        var items = CreateItems(("A", 5.00m, 2), ("B", 3.50m, 4));

        // Act
        var order = _sut.CreateOrder("cust-2", items);

        // Assert — (5*2) + (3.5*4) = 10 + 14 = 24
        Assert.AreEqual(24.00m, order.Total);
        Assert.AreEqual(2, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_ZeroPrice_ReturnsZeroTotal()
    {
        var items = CreateItems(("Free", 0m, 5));

        var order = _sut.CreateOrder("cust-3", items);

        Assert.AreEqual(0m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_ZeroQuantity_ReturnsZeroTotal()
    {
        var items = CreateItems(("Widget", 9.99m, 0));

        var order = _sut.CreateOrder("cust-4", items);

        Assert.AreEqual(0m, order.Total);
    }

    // --- CreateOrder: validation ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 1m, 1));

        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsException<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        var created = _sut.CreateOrder("cust-1", CreateItems(("X", 1m, 1)));

        var found = _sut.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsOnlyMatchingCustomer()
    {
        _sut.CreateOrder("alice", CreateItems(("A", 1m, 1)));
        _sut.CreateOrder("bob", CreateItems(("B", 2m, 1)));
        _sut.CreateOrder("alice", CreateItems(("C", 3m, 1)));

        var aliceOrders = _sut.GetOrdersByCustomer("alice");

        Assert.AreEqual(2, aliceOrders.Count);
        Assert.IsTrue(aliceOrders.All(o => o.CustomerId == "alice"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_UnknownCustomer_ReturnsEmptyList()
    {
        _sut.CreateOrder("alice", CreateItems(("A", 1m, 1)));

        var result = _sut.GetOrdersByCustomer("unknown");

        Assert.AreEqual(0, result.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var result = _sut.GetOrdersByCustomer("anyone");

        Assert.AreEqual(0, result.Count);
    }

    // --- CreateOrder: uniqueness ---

    [TestMethod]
    public void CreateOrder_CalledTwice_AssignsDifferentIds()
    {
        var items = CreateItems(("X", 1m, 1));

        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }
}

